queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?headlines a :Headlines .
    ?headlines p:headline ?headline .
    BIND(?headline AS ?o0)
  }
  UNION
  {
    ?ledes a :Ledes .
    ?ledes p:lede ?lede .
    ?ledes p:Author ?author_f .
    FILTER(STR(?author_f) = "Adam Gopnik")
    BIND(?lede AS ?o0)
  }
}

